import{_ as s,C as t,o as d,c as p,j as e,a as i,E as r,a3 as c}from"./chunks/framework.CVjg771q.js";const z=JSON.parse('{"title":"庄子·德充符","description":"借兀者、恶人与形骸残缺，反看德性如何充实于内。","frontmatter":{"title":"庄子·德充符","description":"借兀者、恶人与形骸残缺，反看德性如何充实于内。","category":"guide","aliases":["德充符","庄子德充符","zhuangzi chapter 05"],"source":["《庄子》","维基文库：庄子·德充符"]},"headers":[],"relativePath":"daoism/zhuang-zi/chapter-05.md","filePath":"daoism/zhuang-zi/chapter-05.md","lastUpdated":1782666543000}'),m={name:"daoism/zhuang-zi/chapter-05.md"};function u(b,a,g,x,f,_){const n=t("DaoReadingPrelude"),o=t("DaoOriginalReadingGroup"),l=t("DaoLineGuide"),h=t("DaoKeywordCards");return d(),p("div",null,[a[0]||(a[0]=e("h1",{id:"庄子·德充符",tabindex:"-1"},[i("庄子·德充符 "),e("a",{class:"header-anchor",href:"#庄子·德充符","aria-label":'Permalink to "庄子·德充符"'},"​")],-1)),r(n,{title:"从形残而德全，进入庄子的德充符",summary:"德充符集中写一批外形不全、容貌丑陋或不合常规的人：王骀、申徒嘉、叔山无趾、哀骀它、支离无脤等。庄子借他们反问：人的完整究竟在形貌、地位与评价中，还是在一种不被外物摇动的德性中？",points:[{label:"先看",text:"顺着王骀、申徒嘉、叔山无趾、哀骀它几组人物，看庄子如何颠倒常人眼光。"},{label:"再问",text:"为什么形体残缺的人，反而能让「全人」忘其形？"},{label:"最后",text:"想一想：你平时判断一个人的完整，是看外在形象，还是看其内在安定？"}],hint:"这一篇不要只看奇人异相，重点在「德有所长，而形有所忘」。"}),a[1]||(a[1]=e("h2",{id:"【原典层】原文",tabindex:"-1"},[i("【原典层】原文 "),e("a",{class:"header-anchor",href:"#【原典层】原文","aria-label":'Permalink to "【原典层】原文"'},"​")],-1)),r(o,{paragraphs:["魯有兀者王駘，從之遊者，與仲尼相若。常季問於仲尼曰：「王駘，兀者也，從之遊者，與夫子中分魯。立不教，坐不議，虛而往，實而歸。固有不言之教，無形而心成者邪？是何人也？仲尼曰：「夫子，聖人也。丘也，直後而未往耳。丘將以為師，而況不如丘者乎！奚假魯國！丘將引天下而與從之。常季曰：「彼兀者也，而王先生，其與庸亦遠矣。若然者，其用心也，獨若之何？","仲尼曰：「死生亦大矣，而不得與之變，雖天地覆墜，亦將不與之遺。審乎無假，而不與物遷，命物之化，而守其宗也。常季曰：「何謂也？仲尼曰：「自其異者視之，肝膽楚越也；自其同者視之，萬物皆一也。夫若然者，且不知耳目之所宜，而游心於德之和，物視其所一，而不見其所喪，視喪其足，猶遺土也。常季曰：「彼為己，以其知得其心，以其心得其常心，物何為最之哉？","仲尼曰：「人莫鑑於流水，而鑑於止水，唯止能止眾止。受命於地，唯松柏獨也在，冬夏青青；受命於天，唯舜獨也正，幸能正生，以正眾生。夫保始之徵，不懼之實。勇士一人，雄入於九軍。將求名而能自要者，而猶若此，而況官天地，府萬物，直寓六骸，象耳目，一知之所知，而心未嘗死者乎！彼且擇日而登假，人則從是也。彼且何肯以物為事乎！申徒嘉，兀者也，而與鄭子產同師於伯昏無人。","子產謂申徒嘉曰：「我先出，則子止；子先出，則我止。其明日，又與合堂同席而坐。子產謂申徒嘉曰：「我先出，則子止；子先出，則我止。今我將出，子可以止乎，其未邪？且子見執政而不違，子齊執政乎？申徒嘉曰：「先生之門，固有執政焉如此哉？子而說子之執政而後人者也！聞之曰：『鑑明則塵垢不止，止則不明也。久與賢人處，則無過。』今子之所取大者，先生也，而猶出言若是，不亦過乎！","子產曰：「子既若是矣，猶與堯爭善，計子之德不足以自反邪？申徒嘉曰：「自狀其過以不當亡者眾，不狀其過以不當存者寡。知不可奈何而安之若命，惟有德者能之。遊於羿之彀中，中央者，中地也，然而不中者，命也。人以其全足笑吾不全足者多矣。我怫然而怒，而適先生之所，則廢然而反。不知先生之洗我以善邪！吾與夫子遊十九年矣，而未嘗知吾兀者也。","今子與我遊於形骸之內，而子索我於形骸之外，不亦過乎！子產蹴然改容更貌曰：「子無乃稱！魯有兀者叔山無趾，踵見仲尼。仲尼曰：「子不謹，前既犯患若是矣。雖今來，何及矣？無趾曰：「吾唯不知務而輕用吾身，吾是以亡足。今吾來也，猶有尊足者存，吾是以務全之也。夫天無不覆，地無不載，吾以夫子為天地，安知夫子之猶若是也！孔子曰：「丘則陋矣。夫子胡不入乎？請講以所聞！無趾出。","孔子曰：「弟子勉之！夫無趾，兀者也，猶務學以復補前行之惡，而況全德之人乎！無趾語老聃曰：「孔丘之於至人，其未邪！彼何賓賓以學子為？彼且蘄以諔詭幻怪之名聞，不知至人之以是為己桎梏邪？老聃曰：「胡不直使彼以死生為一條，以可不可為一貫者，解其桎梏，其可乎？無趾曰：「天刑之，安可解？魯哀公問於仲尼曰：「衛有惡人焉，曰哀駘它。丈夫與之處者，思而不能去也。","婦人見之，請於父母曰『與為人妻，寧為夫子妾』者，十數而未止也。未嘗有聞其唱者也，常和而已矣。無君人之位以濟乎人之死，無聚祿以望人之腹。又以惡駭天下，和而不唱，知不出乎四域，且而雌雄合乎前。是必有異乎人者也。寡人召而觀之，果以惡駭天下。與寡人處，不至以月數，而寡人有意乎其為人也；不至乎期年，而寡人信之。國無宰，寡人傳國焉。悶然而後應，氾而若辭。","寡人醜乎，卒授之國。無幾何也，去寡人而行，寡人卹焉若有亡也，若無與樂是國也。是何人者也？仲尼曰：「丘也，嘗使於楚矣，適見子食於其死母者，少焉眴若，皆棄之而走。不見己焉爾，不得類焉爾。所愛其母者，非愛其形也，愛使其形者也。戰而死者，其人之葬也，不以翣資，刖者之屨，無為愛之，皆無其本矣。為天子之諸御，不爪翦，不穿耳；娶妻者止於外，不得復使。","形全猶足以為爾，而況全德之人乎！今哀駘它未言而信，無功而親，使人授己國，唯恐其不受也，是必才全而德不形者也。哀公曰：「何謂才全？仲尼曰：「死生存亡，窮達貧富，賢與不肖，毀譽、饑渴、寒暑，是事之變，命之行也；日夜相代乎前，而知不能規乎其始者也。故不足以滑和，不可入於靈府。使之和豫通而不失於兌，使日夜無郤而與物為春，是接而生時於心者也。是之謂才全。「何謂德不形？","曰：「平者，水停之盛也。其可以為法也，內保之而外不蕩也。德者，成和之修也。德不形者，物不能離也。哀公異日以告閔子曰：「始也，吾以南面而君天下，執民之紀，而憂其死，吾自以為至通矣。今吾聞至人之言，恐吾無其實，輕用吾身而亡其國。吾與孔丘，非君臣也，德友而已矣。闉跂支離無脤說衛靈公，靈公說之，而視全人，其脰肩肩。甕盎大癭說齊桓公，桓公說之，而視全人，其脰肩肩。","故德有所長，而形有所忘，人不忘其所忘，而忘其所不忘，此謂誠忘。故聖人有所遊，而知為孽，約為膠，德為接，工為商。聖人不謀，惡用知？不斲，惡用膠？無喪，惡用德？不貨，惡用商？四者，天鬻也。天鬻者，天食也。既受食於天，又惡用人？有人之形，無人之情。有人之形，故群於人；無人之情，故是非不得於身。眇乎小哉！所以屬於人也。謷乎大哉！獨成其天。惠子謂莊子曰：「人故無情乎？","莊子曰：「然。惠子曰：「人而無情，何以謂之人？莊子曰：「道與之貌，天與之形，惡得不謂之人？惠子曰：「既謂之人，惡得無情？莊子曰：「是非吾所謂情也。吾所謂無情者，言人之不以好惡內傷其身，常因自然而不益生也。惠子曰：「不益生，何以有其身？莊子曰：「道與之貌，天與之形，無以好惡內傷其身。今子外乎子之神，勞乎子之精，倚樹而吟，據槁梧而瞑。天選子之形，子以堅白鳴！"]}),r(l,{lines:[{label:"王骀",text:"兀者王骀不言而使人实归，提示真正的德不靠言说训诫。"},{label:"申徒嘉",text:"申徒嘉与子产同游，反问人为何只在形骸外寻找别人。"},{label:"无趾",text:"叔山无趾见孔子，提出死生可不可一贯，解其桎梏。"},{label:"哀骀它",text:"哀骀它貌恶而众人亲附，说明才全德不形。"},{label:"诚忘",text:"德有所长而形有所忘，人应忘其所当忘，而不要忘其不可忘。"}]}),a[2]||(a[2]=e("h2",{id:"【原典层】字词释义",tabindex:"-1"},[i("【原典层】字词释义 "),e("a",{class:"header-anchor",href:"#【原典层】字词释义","aria-label":'Permalink to "【原典层】字词释义"'},"​")],-1)),r(h,{items:[{term:"兀者",pinyin:["wù","zhě"],meaning:"受刑断足之人。庄子借兀者反问形体残缺与德性完整的关系。"},{term:"不言之教",pinyin:["bù","yán","zhī","jiào"],meaning:"不用言语训诫，而能使人心有所成。"},{term:"形骸",pinyin:["xíng","hái"],meaning:"人的外在身体形貌。庄子认为执着形骸会遮蔽德性。"},{term:"知不可奈何",pinyin:["zhī","bù","kě","nài","hé"],meaning:"知道有些事不可强改，于是安之若命。"},{term:"才全",pinyin:["cái","quán"],meaning:"内在生命才分完整，不以外貌、功业或地位显露。"},{term:"德不形",pinyin:["dé","bù","xíng"],meaning:"德性充实于内，不必显露成外在形迹。"},{term:"诚忘",pinyin:["chéng","wàng"],meaning:"真正忘掉形貌等外在差别，而不忘内在德性。"}]}),a[3]||(a[3]=c('<h2 id="【原典层】原文底本" tabindex="-1">【原典层】原文底本 <a class="header-anchor" href="#【原典层】原文底本" aria-label="Permalink to &quot;【原典层】原文底本&quot;">​</a></h2><ul><li><a href="https://ctext.org/zhuang-zi/seal-of-virtue-complete/zh" target="_blank" rel="noreferrer">维基文库：庄子·德充符</a></li><li>所属：内篇</li><li>次序：内篇第五篇</li></ul><h2 id="【解读层】三问解读" tabindex="-1">【解读层】三问解读 <a class="header-anchor" href="#【解读层】三问解读" aria-label="Permalink to &quot;【解读层】三问解读&quot;">​</a></h2><h3 id="象-这一篇在说什么" tabindex="-1">象：这一篇在说什么 <a class="header-anchor" href="#象-这一篇在说什么" aria-label="Permalink to &quot;象：这一篇在说什么&quot;">​</a></h3><p>德充符以一组「形不全而德全」的人物为中心，颠倒常人对完整、缺陷、美丑与吸引力的判断。王骀、申徒嘉、叔山无趾、哀骀它等人，外在或残缺或丑陋，却能使人虚而往、实而归。</p><h3 id="理-为什么这一篇重要" tabindex="-1">理：为什么这一篇重要 <a class="header-anchor" href="#理-为什么这一篇重要" aria-label="Permalink to &quot;理：为什么这一篇重要&quot;">​</a></h3><p>这一篇重要，因为它把庄子的「齐物」推进到人的身体与社会评价上。常人以形貌、才能、名声判断人，庄子却说真正使人安定的是德性充实。德一旦充足，形貌就会被忘掉，人的完整不再依赖外在的完整。</p><h3 id="用-今天怎么进入这一篇" tabindex="-1">用：今天怎么进入这一篇 <a class="header-anchor" href="#用-今天怎么进入这一篇" aria-label="Permalink to &quot;用：今天怎么进入这一篇&quot;">​</a></h3><p>今天读德充符，可以反问自己：我是否太容易用外貌、履历、身份判断一个人？我是否也常用外在不完美否定自己？这一篇提醒人，不要把形骸当作全部，人真正能安顿别人、吸引别人之处，在内在德性的稳定。</p><h2 id="【解读层】现代重述" tabindex="-1">【解读层】现代重述 <a class="header-anchor" href="#【解读层】现代重述" aria-label="Permalink to &quot;【解读层】现代重述&quot;">​</a></h2><p>待整理。</p><h2 id="【解读层】我的理解" tabindex="-1">【解读层】我的理解 <a class="header-anchor" href="#【解读层】我的理解" aria-label="Permalink to &quot;【解读层】我的理解&quot;">​</a></h2><p>待整理。</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to &quot;参考来源&quot;">​</a></h2><ul><li>《庄子》</li><li><a href="https://ctext.org/zhuang-zi/seal-of-virtue-complete/zh" target="_blank" rel="noreferrer">维基文库：庄子·德充符</a></li></ul>',15))])}const P=s(m,[["render",u]]);export{z as __pageData,P as default};
